#include <stdio.h>
struct Node {
    int data;
    struct Node* next;
};
int main() {
    struct Node a = {1, NULL};
    struct Node b = {2, NULL};
    struct Node c = {3, NULL};
    struct Node* head = &a;
    a.next = &b;
    b.next = &c;
    head = &c;
    c.next = &a;
    a.next = &b;
    b.next = NULL;
    struct Node* cur = head;
    while (cur != NULL) {
        printf("%d", cur->data);
        cur = cur->next;
    }
    return 0;
}

#include <stdio.h>
void func(int** arr, int size) {
    for (int i = 0; i < size; i++) {
        *(*arr + i) = (*(*arr + i) + i) % size;
    }
}
int main() {
    int arr[] = {3, 1, 4, 1, 5};
    int* p = arr;
    int** pp = &p;
    int num = 6;
    func(pp, 5);
    num = arr[2];
    printf("%d", num);
    return 0;
}

public class ExceptionHandling {
    public static void main(String[] args) {
        int sum = 0;
        try {
            func();
        } catch (NullPointerException e) {
            sum = sum + 1;
        } catch (Exception e) {
            sum = sum + 10;
        } finally {
            sum = sum + 100;
        }
        System.out.print(sum);
    }
    static void func() throws Exception {
        throw new NullPointerException();
    }
}

